// Define a middleware function to validate the 'id' parameter
var validateIdMiddleware = function(req, res, next) {
	// Use the 'params' object to access the 'id' parameter
	var id = req.params.id;
	// Use the 'Number.isInteger' method to validate the 'id' parameter
	if (!Number.isInteger(id) || id <= 0) {
		res.status(400).send('Invalid 'id' parameter');
	} else {
		// Call the next middleware function in the chain
		next();
	}
};
